interface Admin {
  role: 'admin';
  adminLevel: number;
}

interface Guest {
  role: 'guest';
  visitCount: number;
}

type User = Admin | Guest;

function isAdmin(user: User): user is Admin {
  return user.role === 'admin';
}

function greetUser(user: User) {
  if (isAdmin(user)) {
    console.log(`Admin level: ${user.adminLevel}`);
  } else {
    console.log(`Guest visits: ${user.visitCount}`);
  }
}

class CountDown:
    def __init__(self, start):
        self.current = start

    def __iter__(self):
        return self

    def __next__(self):
        if self.current <= 0:
            raise StopIteration
        else:
            self.current -= 1
            return self.current + 1

# Usage
for number in CountDown(5):
    print(number)

def countdown(start):
    current = start
    while current > 0:
        yield current
        current -= 1

# Usage
for number in countdown(5):
    print(number)

class DebugMeta(type):
    def __new__(cls, name, bases, dct):
        print(f"Creating class {name} with bases {bases}")
        # You can inspect or modify dct here
        return super().__new__(cls, name, bases, dct)

class Base(metaclass=DebugMeta):
    pass

class Child(Base):
    pass

